<!DOCTYPE html>
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <style>
      .wiki {
        padding: 0;
        margin: 10px auto 10px auto;
        width: 0;
        height: 0;
        position: absolute;
        opacity: 0;

      }     
       .close {
        padding: 0;
        margin: 10px auto 10px auto;
        width: 160px;
      }

      .close .close-item {
        background-color: #151515;
        background-image: url(https://ik.imagekit.io/zg2sankoh/New%20Folder/light-spots2.png?updatedAt=1752379717873);
        background-position: center;
        background-attachment: fixed;
        outline: 1px solid #fff;
        outline-offset: 1px;
        font-family: "Noto Serif", sans-serif;
        color: #8e8e8e;
        text-align: center;
        letter-spacing: 1px;
        cursor: pointer;
        font-size: 27px;
        height: 33px;
        padding: 6px 0 0 0;
      }

      .close .close-item:hover {
        background-color: #4d4d4d;
      }

      .close .close-item span {
        color: #fff;
        margin: 0;
        font-family: "Noto Serif", sans-serif;
        font-weight: 800;
        display: inline-block;
        width: 100%;
        height: 100%;
      }
    </style>
  </head>
  <body>
    <div class="close">
      <section class="close-item">
        <span risu-trigger="close">CLOSE</span>
      </section>
    </div>
  </body>
</html>
{{/if}}

